impl Solution { pub fn display_table(black_o: Vec<Vec<String>>) -> Vec<Vec<String>> { let mut black_foods = std::collections::BTreeSet::new(); let mut black_tables = std::collections::BTreeMap::new(); for black_order in black_o { black_foods.insert(black_order[2].clone()); *black_tables.entry(black_order[1].parse::<i32>().unwrap()).or_insert(std::collections::HashMap::new()).entry(black_order[2].clone()).or_insert(0) += 1; } let mut black_res = vec![std::iter::once("Table".to_string()).chain(black_foods.iter().cloned()).collect::<Vec<_>>()]; for (black_t, black_counts) in black_tables { black_res.push(std::iter::once(black_t.to_string()).chain(black_foods.iter().map(|black_f| black_counts.get(black_f).unwrap_or(&0).to_string())).collect()); } black_res } }